import React from 'react';
import './world-map.css'
class overworld extends React.Component {
  render() {
    const westmeathMap = [
      [3, 3, 3, 2, 2, 2, 2, 2, 9, 9],
      [3, 3, 30, 0, 0, 0, 0, 0, 0, 8],
      [3, 0, 0, 0, 0, 0, 0, 0, 31, 8],
      [4, 0, 0, 0, 0, 0, 0, 0, 0, 8],
      [4, 0, 0, 0, 0, 0, 0, 34, 0, 8],
      [4, 0, 32, 0, 0, 0, 0, 7, 7, 7],
      [4, 0, 0, 0, 0, 0, 7, 7, 7, 7],
      [5, 0, 0, 0, 33, 7, 7, 7, 7, 7],
      [5, 0, 35, 6, 6, 7, 7, 7, 7, 7],
      [5, 6, 6, 6, 6, 7, 7, 7, 7, 7],
    ];

    return (
      <div className="county-westmeath-map">
        {westmeathMap.map((row, rowIndex) => (
          <div key={`row-${rowIndex}`} className="map-row">
            {row.map((tile, colIndex) => (
              <div key={`col-${colIndex}`} className={`map-tile tile-${tile}`}>
                {tile}
              </div>
            ))}
          </div>
        ))}
      </div>
    );
  }
}

export default overworld;
